<?php declare(strict_types=1);
namespace App\Repositories;
final class StreamRepository extends AbstractRepository { public function active():?array{$s=$this->pdo()->query("SELECT s.*,c.name channel_name,p.name playlist_name FROM streams s JOIN channels c ON c.id=s.channel_id JOIN playlists p ON p.id=s.playlist_id WHERE s.status IN ('queued','starting','running','restarting','stopping') ORDER BY s.id DESC LIMIT 1");return $s->fetch()?:null;} public function latest():?array{$s=$this->pdo()->query('SELECT s.*,c.name channel_name,p.name playlist_name FROM streams s JOIN channels c ON c.id=s.channel_id JOIN playlists p ON p.id=s.playlist_id ORDER BY s.id DESC LIMIT 1');return $s->fetch()?:null;} public function create(int $channel,int $playlist,?string $start,?string $end):int{$s=$this->pdo()->prepare("INSERT INTO streams(channel_id,playlist_id,status,scheduled_start,scheduled_end,stop_requested,restart_requested,pid,restart_count,stopped_at,last_error)VALUES(?,?, 'queued',?,?,0,0,NULL,0,NULL,NULL)");$s->execute([$channel,$playlist,$start,$end]);return(int)$this->pdo()->lastInsertId();} public function update(int $id,array $d):void{$sets=[];$values=[];foreach($d as $k=>$v){$sets[]="$k=?";$values[]=$v;}$values[]=$id;$this->pdo()->prepare('UPDATE streams SET '.implode(',',$sets).' WHERE id=?')->execute($values);} public function find(int $id):?array{$s=$this->pdo()->prepare('SELECT * FROM streams WHERE id=?');$s->execute([$id]);return $s->fetch()?:null;} }
